import{_ as a}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as i,o,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/Safety/cloudflare-api-token.md","filePath":"bn-BD/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"bn-BD/Safety/cloudflare-api-token.md"};function n(c,e,p,s,u,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials থাকলে files বদলানোর পর ImgBed Cloudflare CDN cache purge করতে পারে।</p><p><img src="'+a+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="কোথায়-configure-করবেন" tabindex="-1">কোথায় Configure করবেন <a class="header-anchor" href="#কোথায়-configure-করবেন" aria-label="Permalink to &quot;কোথায় Configure করবেন&quot;">​</a></h2><p>Admin panel খুলে যান:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>আপনাকে এগুলো পূরণ করতে হবে:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="এই-setting-কী-করে" tabindex="-1">এই Setting কী করে <a class="header-anchor" href="#এই-setting-কী-করে" aria-label="Permalink to &quot;এই Setting কী করে&quot;">​</a></h2><p>Cloudflare public image URLs cache করতে পারে।</p><p>Caching image delivery দ্রুত করে, কিন্তু file delete, block, replace বা move করার পরও পুরোনো content কিছু সময় visible থাকতে পারে।</p><p>Cloudflare API credentials configured থাকলে ওই operations শেষ হওয়ার পর ImgBed related Cloudflare cache purge করার চেষ্টা করে।</p><p>এটি কাজে লাগে যখন:</p><ul><li>Image delete করেছেন এবং public link যত দ্রুত সম্ভব বন্ধ হোক চান।</li><li>Image block করেছেন এবং visitors যেন original file না দেখে চান।</li><li>একই নামের file replace করেছেন এবং visitors যেন দ্রুত নতুন version দেখে চান।</li><li>Files move বা rename করেছেন এবং old path cache দ্রুত refresh করতে চান।</li><li>Public access rules বদলেছেন এবং public gallery বা random image cache দ্রুত update করতে চান।</li></ul><h2 id="empty-রাখলে-কী-হবে" tabindex="-1">Empty রাখলে কী হবে <a class="header-anchor" href="#empty-রাখলে-কী-হবে" aria-label="Permalink to &quot;Empty রাখলে কী হবে&quot;">​</a></h2><p>এই setting ছাড়া ImgBed normalভাবে কাজ করবে।</p><p>ফারাক হলো ImgBed Cloudflare CDN cache actively purge করবে না। Cloudflare cache নিজে expire না হওয়া পর্যন্ত visitors পুরোনো content দেখতে পারে।</p><h2 id="zone-id-কীভাবে-পাবেন" tabindex="-1">Zone ID কীভাবে পাবেন <a class="header-anchor" href="#zone-id-কীভাবে-পাবেন" aria-label="Permalink to &quot;Zone ID কীভাবে পাবেন&quot;">​</a></h2><p>Zone ID হলো আপনার ImgBed domain যে site ব্যবহার করছে, সেই site-এর Cloudflare Zone ID।</p><ol><li>Cloudflare dashboard-এ sign in করুন।</li><li>আপনার ImgBed domain থাকা site খুলুন।</li><li>Site overview page-এ <code>Zone ID</code> খুঁজুন।</li><li>ImgBed-এর <code>Zone ID</code> field-এ copy করুন।</li></ol><p>এটি site Zone ID, account ID নয়।</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Cloudflare-এ sign in করতে যে email address ব্যবহার করেন সেটি দিন।</p><p>এটি নিচে দেওয়া API Key-এর সঙ্গে match করতে হবে।</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>আপনার Cloudflare Global API Key দিন।</p><ol><li>Cloudflare dashboard-এ sign in করুন।</li><li>Profile খুলুন।</li><li>API Tokens page-এ যান।</li><li><code>Global API Key</code> খুঁজুন।</li><li>View করে copy করুন।</li><li>ImgBed-এর <code>API Key</code> field-এ paste করুন।</li></ol><p><img src="'+l+'" alt="View global API key" loading="lazy"></p><h2 id="কখন-কার্যকর-হয়" tabindex="-1">কখন কার্যকর হয় <a class="header-anchor" href="#কখন-কার্যকর-হয়" aria-label="Permalink to &quot;কখন কার্যকর হয়&quot;">​</a></h2><p>Fields পূরণ করার পর settings save করুন।</p><p>এরপর future file changes হলে ImgBed automatically Cloudflare cache purge করার চেষ্টা করবে। Past operations retroactively purge হয় না। Setup-এর আগে file delete বা replace করে থাকলে Cloudflare cache expire হওয়া পর্যন্ত অপেক্ষা করুন, অথবা Cloudflare-এ manually purge করুন।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="এটি-কি-required" tabindex="-1">এটি কি Required? <a class="header-anchor" href="#এটি-কি-required" aria-label="Permalink to &quot;এটি কি Required?&quot;">​</a></h3><p>না।</p><p>আপনার domain Cloudflare ব্যবহার না করলে, বা CDN cache delay নিয়ে সমস্যা না থাকলে empty রাখতে পারেন।</p><h3 id="wrong-credentials-কি-uploads-ভেঙে-দেবে" tabindex="-1">Wrong Credentials কি Uploads ভেঙে দেবে? <a class="header-anchor" href="#wrong-credentials-কি-uploads-ভেঙে-দেবে" aria-label="Permalink to &quot;Wrong Credentials কি Uploads ভেঙে দেবে?&quot;">​</a></h3><p>সাধারণত না।</p><p>Wrong credentials শুধু ImgBed-কে Cloudflare cache purge করা থেকে আটকাবে। Upload এবং normal file access চলতে থাকা উচিত।</p><h3 id="deleted-image-এখনও-কেন-খোলে" tabindex="-1">Deleted Image এখনও কেন খোলে? <a class="header-anchor" href="#deleted-image-এখনও-কেন-খোলে" aria-label="Permalink to &quot;Deleted Image এখনও কেন খোলে?&quot;">​</a></h3><p>সবচেয়ে common কারণ হলো Cloudflare-এর কাছে পুরোনো file cached আছে।</p><p>সঠিক Cloudflare API credentials থাকলে file delete করার সময় ImgBed related URL cache purge করে।</p><h3 id="file-replace-করার-পরও-পুরোনো-image-কেন-দেখাচ্ছে" tabindex="-1">File replace করার পরও পুরোনো Image কেন দেখাচ্ছে? <a class="header-anchor" href="#file-replace-করার-পরও-পুরোনো-image-কেন-দেখাচ্ছে" aria-label="Permalink to &quot;File replace করার পরও পুরোনো Image কেন দেখাচ্ছে?&quot;">​</a></h3><p>এটিও সাধারণত CDN cache-এর কারণে হয়।</p><p>এই setting configured হলে একই নামের file overwrite করার সময় ImgBed old URL cache purge করার চেষ্টা করে।</p>',44)])])}const I=i(d,[["render",n]]);export{b as __pageData,I as default};
